class.description:
[ResourceExporter] is the base class for individual export plugin implementations. Extend it to add support for exporting a new resource type from a loaded Godot project back to its original source format. Registered exporters are dispatched through the global [Exporter] registry.
To add a new exporter, implement [method get_name], [method handles_import], [method get_export_extensions], [method get_default_export_extension], [method supports_nonpack_export], and at least one of [method export_file] / [method export_resource]. Then register your instance with [method Exporter.add_exporter].
[codeblock]
class_name MyCustomExporter
extends ResourceExporter

func get_name() -> String:
    return "MyCustomExporter"

func handles_import(importer: String, resource_type: String) -> bool:
    return importer == "my_custom_importer"

func get_export_extensions(res_path: String) -> PackedStringArray:
    return PackedStringArray(["bin"])

func get_default_export_extension(res_path: String) -> String:
    return "bin"

func supports_nonpack_export() -> bool:
    return false

func export_file(out_path: String, src_path: String) -> Error:
    return OK

Exporter.add_exporter(MyCustomExporter.new(), false)
[/codeblock]
